const agentOutput = $input.first().json.output || {};
const lead = $('Get Leads - Stage 2 Ready').item.json;

// Calculate initial AI score
let aiScore = 0;
if (agentOutput.company_size === 'medium' || agentOutput.company_size === 'large') aiScore += 20;
if (agentOutput.recent_activity && agentOutput.recent_activity !== 'None') aiScore += 15;
if (agentOutput.linkedin_url) aiScore += 10;
if (agentOutput.pain_points && agentOutput.pain_points.length >= 3) aiScore += 10;

// Safely format pain_points array for PostgreSQL
const painPoints = Array.isArray(agentOutput.pain_points) ? agentOutput.pain_points : [];
const painPointsSQL = painPoints.length > 0
  ? `ARRAY[${painPoints.map(p => `'${String(p).replace(/'/g, "''")}'`).join(',')}]`
  : 'NULL';

// Safely format growth_signals array for PostgreSQL
const growthSignals = Array.isArray(agentOutput.growth_signals) ? agentOutput.growth_signals : [];
const growthSignalsSQL = growthSignals.length > 0
  ? `ARRAY[${growthSignals.map(s => `'${String(s).replace(/'/g, "''")}'`).join(',')}]`
  : 'NULL';

// Parse linkedin_followers safely
let linkedinFollowers = null;
if (agentOutput.linkedin_followers && agentOutput.linkedin_followers !== 'unknown') {
  const parsed = parseInt(agentOutput.linkedin_followers);
  linkedinFollowers = isNaN(parsed) ? null : parsed;
}

return {
  lead_id: lead.id,
  products_services: agentOutput.products_services || null,
  target_customer: agentOutput.target_customer || null,
  pain_points_sql: painPointsSQL,
  recent_news: agentOutput.recent_news || agentOutput.recent_activity || null,
  company_size: agentOutput.company_size || null,
  decision_maker_access: agentOutput.decision_maker || agentOutput.decision_maker_access || null,
  personalization_hook: agentOutput.personalization_hook || null,
  company_linkedin_url: agentOutput.linkedin_url || agentOutput.company_linkedin_url || null,
  linkedin_employee_count: agentOutput.linkedin_employee_count || null,
  linkedin_industry: agentOutput.linkedin_industry || null,
  linkedin_description: agentOutput.linkedin_description || null,
  twitter_url: agentOutput.twitter_url || null,
  crunchbase_url: agentOutput.crunchbase_url || null,
  recent_funding: agentOutput.recent_funding || null,
  growth_signals_sql: growthSignalsSQL,
  ai_research_score: aiScore,
  enrichment_stage: 2
};

